<template>
    <view class="contain">
        <view class="tabs">
            <view class="tab" :class="current == 1? 'active' : '' " @click="changeTab(1)">
                <view class="tabImage">
                    <image v-if="current == 1" src="../../../../static/icons/messageA.png" mode=""></image>
                    <image v-else src="../../../../static/icons/essage.png" mode=""></image>
                </view>
                <view class="tabText">
                    テキスト
                </view>
            </view>
            <view class="tab" :class="current == 2? 'active' : '' " @click="changeTab(2)">
                <view class="tabImage">
                    <image v-if="current == 2" src="../../../../static/icons/imageA.png" mode=""></image>
                    <image v-else src="../../../../static/icons/image.png" mode=""></image>
                </view>
                <view class="tabText">
                    写真・画像
                </view>
            </view>
        </view>
        <view class="content" v-if="current == 1">
            <view class="item">
                <view class="itemTitle">
                    <text class="icon">※</text>
                    <text>タイトル </text>
                    <text class="fu">(タイトルはメッセージに反映されません)</text>
                </view>
                <u-input v-model="info.title" placeholder="タイトルを入力してください"></u-input>
            </view>

            <view class="item">
                <view class="itemTitle">
                    <text class="icon">※</text>
                    <text>テキ </text>
                </view>
                <u-textarea :placeholder="value2" v-model="info.content" height="395"></u-textarea>
            </view>
        </view>

        <view class="content" v-if="current == 2">
            <view class="item">
                <view class="itemTitle">
                    <text class="icon">※</text>
                    <text>タイトル </text>
                    <text class="fu">(タイトルはメッセージに反映されません)</text>
                </view>
                <u-input v-model="info.title" placeholder="タイトルを入力してください"></u-input> 
            </view>

            <view class="item">
                <view class="itemTitle">
                    <text class="icon">※</text>
                    <text>画像 </text>
                </view>
                <view class="upload" @click="uploadImage">
                    <view style="color: #aaa;" v-if="info.image == '../../../../static/icons/image.png'">
                        画像
                    </view>
                    <view v-if="info.image == '../../../../static/icons/image.png'">
                        <image class="upimage" :src="info.image" mode=""></image>
                    </view>
                    <view class="uploadImage" v-if="info.image != '../../../../static/icons/image.png'">
                        <image :src="info.image" mode="aspectFit"></image>
                    </view>
                </view>
            </view>
            <view class="item">
                <view class="itemTitle">
                    <text>url </text>
                </view>
                <u-input border="bottom" v-model="info.url" placeholder="タイトルを入力してください"></u-input>
            </view>
        </view>
        <u-button type="success" @click="toNext" color="#34C759" class="btn">次へ</u-button>
        <u-popup :round="30" :show="show" @close="close" mode="bottom">
            <view class="modualContent">
                <view class="mTitle">
                    <image @click="close" class="mClose" src="../../../../static/icons/tclose.png" mode=""></image>
                    <view class="mWord">
                        プレビュー
                    </view>
                </view>
                <view class="mContent">
                    <view class="mTip">
                        端末やOSによっては、実際に表示される画面と異なる場合があります。
                    </view>
                    <view class="mDetail">
                        <u-avatar src="../../../../static/icons/user.png" size="30"></u-avatar>
                        <view class="mChat" v-text="info.content"></view>
                    </view>
                </view>
            </view>
        </u-popup>
    </view>
</template>
<script>
    import {getTimingDetail} from "@/api/index.js"
    export default {
        data() {
            return {
                current: 1,
                status: "create",
                show: false,
                value2: "テキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキストテキスト",
                query:{},
                info:{
                    title:"",
                    content:"",
                    url:"",
                    image:"../../../../static/icons/image.png"
                }
            }
        },
        onNavigationBarButtonTap(e) {
            console.log(e)
            let that = this
            that.show = true
        },
        created() {
            
        },
        onLoad(options) {
           let that = this
           let query = options
           that.query = query
           if(query.source == "edit"){
               that.getDetail(query.id)
           } 
        },
        methods: {
            changeTab(e) {
                if (this.status == 'create') {
                    this.current = e
                }
            },
            
            getDetail(id){
                let that = this 
                getTimingDetail(id).then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        let data = {}
                        data = JSON.parse(JSON.stringify(res.data.timing_message)) 
                        if(res.data.timing_message.content_type == 2){
                            data.image = res.data.timing_message.content
                            data.content = ""
                        }
                        that.info = data
                        that.current = data.content_type
                        uni.setStorageSync("timing",res.data.timing_message)
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none"
                        })
                    }
                }) 
            },
            
            close() {
                let that = this
                that.show = false
            },
            toNext() {
                let that = this
                if(that.query.source == "add"){
                    let data = {}
                    data.title = that.info.title
                    data.content_type = that.current
                    if(that.current == 1){
                        data.content = that.info.content
                        data.url = ""
                    }else{
                        data.content = that.info.image
                        data.url = that.info.url
                    }
                    uni.setStorageSync("timing",data)
                    uni.navigateTo({
                        url: "../setting/setting?source=add"
                    })
                }else if(that.query.source == "edit"){
                    uni.navigateTo({
                        url: "../setting/setting?source=edit&id="+that.query.id
                    })
                }
            },
            uploadImage() {
                let that = this
                uni.chooseImage({
                    count: 1,
                    success: (res) => {
                        const tempPaths = res.tempFilePaths
                        uni.uploadFile({
                            url: that.$baseUrl+'/tool/upload/file',
                            filePath: res.tempFilePaths[0],
                            name:"file",
                            success: (result) => {
                                if (result.errMsg == "uploadFile:ok") {
                                    let re = JSON.parse(result.data)
                                    if (re.code == 200) {
                                        console.log(re)
                                        that.info.image = re.data.path
                                    }
                                }
                            }
                        })
                    }
                });
            },
        }
    }
</script>

<style lang="scss">
    .uploadImage{
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
    }
    
    .mTitle {
        display: flex;
        align-items: center;
        text-align: center;
        box-sizing: border-box;
        padding: 26upx 32upx;
        background: #FBFBFD;
        border-top-left-radius: 60upx;
        border-top-right-radius: 60upx;
        font-size: 40upx;
        font-family: Hiragino Sans-W5, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        border-bottom: 2upx solid #d2d2d7;

        .mClose {
            width: 60upx;
            height: 60upx;
            border-radius: 50%;
        }

        .mWord {
            flex: 1;
        }
    }

    .mContent {
        width: 100%;
        height: 1000upx;
        background: #fff;

        .mTip {
            width: 686upx;
            height: 52upx;
            background: #707070;
            border-radius: 16upx;
            font-size: 20upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #FFFFFF;
            text-align: center;
            line-height: 52upx;
            margin: 52upx auto 60upx;
        }

        .mDetail {
            display: flex;
            align-items: flex-start;
            box-sizing: border-box;
            padding: 0 38upx;

            .mAvatar {
                width: 60upx;
                height: 60upx;
            }

            .mChat {
                margin-left: 6upx;
                background: rgba(143, 168, 248, 0.2);
                box-sizing: border-box;
                padding: 20upx;
                max-width: 492upx;
                font-size: 32upx;
                font-family: Hiragino Sans-W3, Hiragino Sans;
                font-weight: normal;
                color: #1D1D1F;
                border-radius: 20upx;
            }
        }
    }

    .upload {
        width: 100%;
        height: 646upx;
        border: 2upx solid #aaa;
        border-radius: 12upx;
        text-align: center;
        box-sizing: border-box;
        padding-top: 200upx;
        position: relative;

        .upimage {
            width: 126upx;
            height: 120upx;
        }
    }

    .content {
        box-sizing: border-box;
        padding: 60upx 52upx;

        .item {
            margin-bottom: 32upx;
        }

        .itemTitle {
            font-size: 28upx;
            color: #707070;
            margin-bottom: 10upx;

            .icon {
                color: #D93025;
            }

            .fu {
                font-size: 24upx;
                color: #aaa;
            }
        }
    }

    .btn {
        width: 480upx;
        height: 96upx;
        margin-bottom: 80upx;
    }

    .tabs {
        height: 120upx;
        background-color: #FFFFFF;
        display: flex;
        border-top: 2upx solid #D2D2D7;
        border-bottom: 2upx solid #D2D2D7;

        .active {
            background: rgba(29, 29, 31, 0.1);
            color: #1D1D1F !important;
        }

        .tab {
            display: flex;
            align-items: center;
            flex: 1;
            justify-content: center;
            color: rgba(29, 29, 31, 0.3);

            .tabImage {
                width: 42upx;
                height: 40upx;
                margin-right: 16upx;

                image {
                    width: 100%;
                    height: 100%;
                }
            }
        }
    }
</style>
